patch:
--- a/mux_selector.v
+++ b/mux_selector.v
@@ -1,12 +1,12 @@
 module mux_16bit(
     input [15:0] data0,
     input [15:0] data1,
     input [15:0] data2,
     input [15:0] data3,
     input [1:0] sel,
     output reg [15:0] out
 );

-    always @(sel) begin
+    always @(sel or data0 or data1 or data2 or data3) begin
         case(sel)
             2'b00: out = data0;
             2'b01: out = data1;
             2'b10: out = data2;
             2'b11: out = data3;
         endcase

before_code:
module mux_16bit(
    input [15:0] data0,
    input [15:0] data1,
    input [15:0] data2,
    input [15:0] data3,
    input [1:0] sel,
    output reg [15:0] out
 );

    always @(sel) begin
        case(sel)
            2'b00: out = data0;
            2'b01: out = data1;
            2'b10: out = data2;
            2'b11: out = data3;
        endcase
    end

endmodule

after_code:
module mux_16bit(
    input [15:0] data0,
    input [15:0] data1,
    input [15:0] data2,
    input [15:0] data3,
    input [1:0] sel,
    output reg [15:0] out
 );

    always @(sel or data0 or data1 or data2 or data3) begin
        case(sel)
            2'b00: out = data0;
            2'b01: out = data1;
            2'b10: out = data2;
            2'b11: out = data3;
        endcase
    end

endmodule
